import{bQ as d,aL as r,u as e,G as a}from"./chunks/framework.D06dwy5q.js";const b=JSON.parse('{"title":"存储选型与接入","description":"","frontmatter":{},"headers":[],"relativePath":"11.分布式存储/05-存储选型与接入.md","filePath":"11.分布式存储/05-存储选型与接入.md","lastUpdated":null}'),o={name:"11.分布式存储/05-存储选型与接入.md"};function h(E,t,i,c,l,s){return r(),e("div",null,[...t[0]||(t[0]=[a('<h1 id="存储选型与接入" tabindex="-1">存储选型与接入 <a class="header-anchor" href="#存储选型与接入" aria-label="Permalink to &quot;存储选型与接入&quot;">​</a></h1><p>存储选型从数据访问方式开始区分：应用需要的是&quot;块&quot;、&quot;文件&quot;还是&quot;对象&quot;，三者不能互相替代。然后再看容量、性能、可用性、备份、团队维护能力和接入 K8s 的方式。</p><h2 id="三种存储语义" tabindex="-1">三种存储语义 <a class="header-anchor" href="#三种存储语义" aria-label="Permalink to &quot;三种存储语义&quot;">​</a></h2><table tabindex="0"><thead><tr><th>类型</th><th>形式</th><th>常见实现</th><th>典型场景</th></tr></thead><tbody><tr><td>块存储</td><td>远端磁盘</td><td>云盘、Ceph RBD、SAN</td><td>数据库数据盘、虚拟机磁盘、K8s RWO</td></tr><tr><td>文件存储</td><td>共享目录</td><td>NFS、CephFS、NAS</td><td>共享附件、制品、多 Pod 共享读写</td></tr><tr><td>对象存储</td><td>S3 API</td><td>MinIO、Ceph RGW、云 OSS/S3</td><td>备份、图片、日志归档、数据交换</td></tr></tbody></table><div class="mermaid-diagram" data-mermaid-code="flowchart%20LR%0A%20%20%20%20app%5B%22%E5%BA%94%E7%94%A8%E8%AF%BB%E5%86%99%E9%9C%80%E6%B1%82%22%5D%20--%3E%20block%5B%22%E5%9D%97%E5%AD%98%E5%82%A8%3Cbr%2F%3E%E5%83%8F%E4%B8%80%E5%9D%97%E7%9B%98%EF%BC%9A%2Fdev%2Frbd0%20%E2%86%92%20mkfs%20%E2%86%92%20mount%22%5D%0A%20%20%20%20app%20--%3E%20file%5B%22%E6%96%87%E4%BB%B6%E5%AD%98%E5%82%A8%3Cbr%2F%3E%E5%83%8F%E4%B8%80%E4%B8%AA%E5%85%B1%E4%BA%AB%E7%9B%AE%E5%BD%95%EF%BC%9Amount%20%E8%BF%9C%E7%AB%AF%E8%B7%AF%E5%BE%84%E5%88%B0%E6%9C%AC%E5%9C%B0%22%5D%0A%20%20%20%20app%20--%3E%20object%5B%22%E5%AF%B9%E8%B1%A1%E5%AD%98%E5%82%A8%3Cbr%2F%3E%E9%80%9A%E8%BF%87%20HTTP%20API%20%E5%AD%98%E5%8F%96%E5%AF%B9%E8%B1%A1%EF%BC%9APUT%2FGET%2FDELETE%20key%22%5D%0A"></div><p>三种语义的边界很关键：对象存储不适合当数据库盘（不是块设备，不支持 <code>fsync</code> 语义）；块存储不适合多节点直接同时挂载（需要集群文件系统或应用协议配合）；NFS 看起来像目录但不等于高性能分布式文件系统。</p><h2 id="常见方案对比" tabindex="-1">常见方案对比 <a class="header-anchor" href="#常见方案对比" aria-label="Permalink to &quot;常见方案对比&quot;">​</a></h2><table tabindex="0"><thead><tr><th>方案</th><th>存储类型</th><th>优点</th><th>风险</th></tr></thead><tbody><tr><td>本地盘</td><td>块/文件</td><td>延迟低、简单</td><td>节点坏了数据跟着受影响</td></tr><tr><td>云盘</td><td>块</td><td>托管稳定、快照方便</td><td>可用区限制、成本</td></tr><tr><td>NFS</td><td>文件</td><td>简单直观、接入快</td><td>单点、权限映射、小文件性能</td></tr><tr><td>Ceph RBD</td><td>块</td><td>分布式块存储，副本保护</td><td>运维成本和恢复复杂度</td></tr><tr><td>CephFS</td><td>文件</td><td>分布式共享文件系统</td><td>MDS 元数据压力</td></tr><tr><td>MinIO</td><td>对象</td><td>S3 兼容、适合备份和制品</td><td>非 POSIX、应用要适配 S3 API</td></tr><tr><td>Ceph RGW</td><td>对象</td><td>和 Ceph 共用集群底座</td><td>Ceph 运维门槛</td></tr><tr><td>NAS</td><td>文件</td><td>厂商支持、硬件托管</td><td>成本、黑盒、扩展方式受限</td></tr></tbody></table><p>GlusterFS（Red Hat Gluster Storage）已于 2024-12-31 EOL。存量环境按现状维护，新建设施不再优先考虑。</p><h2 id="按场景选型" tabindex="-1">按场景选型 <a class="header-anchor" href="#按场景选型" aria-label="Permalink to &quot;按场景选型&quot;">​</a></h2><table tabindex="0"><thead><tr><th>场景</th><th>常见选择</th><th>为什么</th></tr></thead><tbody><tr><td>MySQL/PostgreSQL 单实例</td><td>云盘、Ceph RBD、本地盘</td><td>需要稳定块设备和低 fsync 延迟</td></tr><tr><td>Redis 持久化</td><td>云盘、本地盘、Ceph RBD</td><td>看延迟要求和恢复方式</td></tr><tr><td>多副本无状态临时数据</td><td>emptyDir、本地盘</td><td>数据可丢，重点在性能</td></tr><tr><td>多 Pod 共享附件</td><td>NFS、CephFS、NAS</td><td>需要 RWX 文件语义</td></tr><tr><td>备份文件</td><td>MinIO、云对象存储、NFS</td><td>对象存储版本和生命周期更适合长期保留</td></tr><tr><td>镜像仓库</td><td>本地盘、云盘、对象存储后端</td><td>看 Harbor/Registry 支持的后端</td></tr><tr><td>日志归档</td><td>对象存储、HDFS 类</td><td>大量追加后归档，不频繁访问</td></tr><tr><td>K8s RWO PVC</td><td>云盘 CSI、Ceph RBD CSI</td><td>单 Pod/单节点读写</td></tr><tr><td>K8s RWX PVC</td><td>NFS、CephFS、NAS CSI</td><td>多节点共享目录</td></tr></tbody></table><p>核心数据库选存储，低延迟和故障恢复比&quot;能不能共享&quot;更重要。NFS 能挂上不等于适合跑数据库；对象存储能存文件不等于适合应用当目录写。</p><h2 id="选型前需要回答的问题" tabindex="-1">选型前需要回答的问题 <a class="header-anchor" href="#选型前需要回答的问题" aria-label="Permalink to &quot;选型前需要回答的问题&quot;">​</a></h2><table tabindex="0"><thead><tr><th>问题</th><th>为什么重要</th></tr></thead><tbody><tr><td>数据是否可丢？</td><td>决定副本数、快照频率、备份策略和恢复投入</td></tr><tr><td>是否多节点同时读写？</td><td>直接决定块还是文件——RWO vs RWX</td></tr><tr><td>IO 模式是什么？</td><td>顺序写 vs 随机写，大文件 vs 小文件，差异巨大</td></tr><tr><td>延迟要求多高？</td><td>数据库 2ms 和归档 200ms 是两种方案</td></tr><tr><td>容量增长速度？</td><td>决定扩容方式和成本——MinIO 按 pool 扩和云盘按 GB 扩不同</td></tr><tr><td>谁来维护？</td><td>Ceph 的维护成本和 NAS 的厂商支持是两种投入</td></tr><tr><td>怎么备份？</td><td>存储高可用不等于备份——多副本挡不住误删</td></tr><tr><td>怎么恢复？</td><td>RTO/RPO 要落到具体命令和演练，不是纸上指标</td></tr></tbody></table><p>存储事故里最常见的是&quot;有高可用，没有备份&quot;。三副本能防磁盘坏，防不了误删、误覆盖、勒索加密和应用写坏数据。</p><h2 id="k8s-接入链路" tabindex="-1">K8s 接入链路 <a class="header-anchor" href="#k8s-接入链路" aria-label="Permalink to &quot;K8s 接入链路&quot;">​</a></h2><div class="mermaid-diagram" data-mermaid-code="flowchart%20LR%0A%20%20%20%20pod%5B%22Pod%22%5D%20--%3E%20pvc%5B%22PVC%3Cbr%2F%3E%E5%AE%B9%E9%87%8F%E5%92%8C%E8%AE%BF%E9%97%AE%E6%A8%A1%E5%BC%8F%22%5D%0A%20%20%20%20pvc%20--%3E%20pv%5B%22PV%22%5D%0A%20%20%20%20pv%20--%3E%20sc%5B%22StorageClass%3Cbr%2F%3E%E5%8A%A8%E6%80%81%E4%BE%9B%E7%BB%99%E6%A8%A1%E6%9D%BF%22%5D%0A%20%20%20%20sc%20--%3E%20backend%5B%22%E7%9C%9F%E5%AE%9E%E5%90%8E%E7%AB%AF%3Cbr%2F%3E%E4%BA%91%E7%9B%98%20%2F%20Ceph%20%2F%20NFS%20%2F%20NAS%22%5D%0A"></div><table tabindex="0"><thead><tr><th>后端</th><th>K8s 接入</th><th>常见访问模式</th></tr></thead><tbody><tr><td>云盘</td><td>云厂商 CSI</td><td>RWO</td></tr><tr><td>Ceph RBD</td><td>ceph-csi rbd</td><td>RWO</td></tr><tr><td>CephFS</td><td>ceph-csi cephfs</td><td>RWX</td></tr><tr><td>NFS</td><td>静态 PV 或 nfs-subdir provisioner</td><td>RWX</td></tr><tr><td>NAS</td><td>厂商 CSI 或 NFS 协议</td><td>RWX</td></tr><tr><td>Local PV</td><td>local provisioner / 静态 PV</td><td>RWO</td></tr></tbody></table><p>PVC Bound 只说明对象绑定成功。后端 IO 是否健康，要单独验证——挂载成功、权限正确、读写正常，一层一层确认。</p><h2 id="访问模式与后端的真实关系" tabindex="-1">访问模式与后端的真实关系 <a class="header-anchor" href="#访问模式与后端的真实关系" aria-label="Permalink to &quot;访问模式与后端的真实关系&quot;">​</a></h2><p>K8s 访问模式是对后端能力的抽象，不是 PVC 写了 RWX 后端就自动支持：</p><table tabindex="0"><thead><tr><th>模式</th><th>含义</th><th>常见支持后端</th></tr></thead><tbody><tr><td>RWO</td><td>单节点读写</td><td>云盘、Ceph RBD、Local PV</td></tr><tr><td>RWX</td><td>多节点读写</td><td>NFS、CephFS、NAS</td></tr><tr><td>ROX</td><td>多节点只读</td><td>NFS、CephFS</td></tr><tr><td>RWOP</td><td>单 Pod 独占读写</td><td>较新的 CSI 特性</td></tr></tbody></table><p>很多云盘只支持 RWO。应用层也要匹配：多个 Pod 同时写同一个共享目录，应用自己没做并发写控制，存储支持 RWX 也不代表数据不乱。</p><h2 id="备份和保护的层次" tabindex="-1">备份和保护的层次 <a class="header-anchor" href="#备份和保护的层次" aria-label="Permalink to &quot;备份和保护的层次&quot;">​</a></h2><p>几个概念要区分开，它们解决不同层面的问题：</p><table tabindex="0"><thead><tr><th>概念</th><th>解决什么问题</th><th>解决不了什么问题</th></tr></thead><tbody><tr><td>副本（多副本/RAID）</td><td>磁盘或节点故障</td><td>误删、误改、应用写坏</td></tr><tr><td>快照</td><td>某个时间点的状态保存</td><td>存储集群整体的灾难</td></tr><tr><td>备份（独立副本）</td><td>误删、集群故障、灾难恢复</td><td>需要恢复演练来验证</td></tr><tr><td>复制（跨集群/跨区域）</td><td>站点级故障</td><td>源端逻辑损坏可能同步到副本</td></tr><tr><td>归档</td><td>长期保留、合规</td><td>恢复速度慢</td></tr></tbody></table><p>不同后端常见保护方式：</p><table tabindex="0"><thead><tr><th>后端</th><th>常见保护</th></tr></thead><tbody><tr><td>云盘</td><td>定期快照、跨区复制、备份服务</td></tr><tr><td>Ceph RBD</td><td>镜像快照、rbd mirror、外部备份</td></tr><tr><td>CephFS</td><td>目录快照、rsync、对象存储备份</td></tr><tr><td>NFS</td><td>底层快照 + rsync 保留多版本 + 对象存储</td></tr><tr><td>MinIO</td><td>versioning、replication、lifecycle、object lock</td></tr></tbody></table><p>误删数据时，最重要的是有没有独立备份和恢复演练。&quot;底层三副本&quot;救不了 <code>DELETE FROM</code> 或 <code>rm -rf</code>。</p><h2 id="性能瓶颈定位" tabindex="-1">性能瓶颈定位 <a class="header-anchor" href="#性能瓶颈定位" aria-label="Permalink to &quot;性能瓶颈定位&quot;">​</a></h2><p>不同存储类型的瓶颈点不同，排查要找准对应的工具：</p><table tabindex="0"><thead><tr><th>类型</th><th>常见瓶颈</th><th>定位工具</th></tr></thead><tbody><tr><td>本地盘</td><td>单盘 IO、inode、文件系统</td><td><code>iostat</code>、<code>df -i</code></td></tr><tr><td>云盘</td><td>IOPS/吞吐规格、突发额度</td><td>云厂商监控、<code>iostat</code></td></tr><tr><td>NFS</td><td>服务端磁盘、网络、同步写、小文件</td><td><code>nfsiostat</code>、<code>iostat</code></td></tr><tr><td>Ceph RBD</td><td>OSD 延迟、网络、PG recovery</td><td><code>ceph osd perf</code>、<code>ceph -s</code></td></tr><tr><td>CephFS</td><td>MDS 元数据、目录规模、OSD 延迟</td><td><code>ceph fs status</code>、<code>ceph mds stat</code></td></tr><tr><td>MinIO</td><td>磁盘、网络、对象大小、入口超时</td><td><code>mc admin info</code></td></tr></tbody></table><p>用 <code>fio</code> 压测时要贴近真实 IO 模式。大文件顺序写的结果不能代表小文件随机写的表现——数据库和对象归档的 IO 模式完全不同。</p><h2 id="故障排查分层" tabindex="-1">故障排查分层 <a class="header-anchor" href="#故障排查分层" aria-label="Permalink to &quot;故障排查分层&quot;">​</a></h2><p>应用报 <code>Input/output error</code> 时，原因可能出在客户端挂载、CSI、网络、后端服务或磁盘的任意一层：</p><div class="mermaid-diagram" data-mermaid-code="flowchart%20LR%0A%20%20%20%20app%5B%22%E5%BA%94%E7%94%A8%E6%8A%A5%E9%94%99%22%5D%20--%3E%20mount%5B%22%E5%AE%A2%E6%88%B7%E7%AB%AF%E6%8C%82%E8%BD%BD%20%2F%20PVC%22%5D%0A%20%20%20%20mount%20--%3E%20driver%5B%22CSI%20%2F%20%E5%8D%8F%E8%AE%AE%E5%AE%A2%E6%88%B7%E7%AB%AF%22%5D%0A%20%20%20%20driver%20--%3E%20network%5B%22%E7%BD%91%E7%BB%9C%E5%B1%82%22%5D%0A%20%20%20%20network%20--%3E%20backend%5B%22%E5%AD%98%E5%82%A8%E5%90%8E%E7%AB%AF%E6%9C%8D%E5%8A%A1%22%5D%0A%20%20%20%20backend%20--%3E%20disk%5B%22%E7%A3%81%E7%9B%98%20%2F%20Pool%20%2F%20Bucket%22%5D%0A"></div><table tabindex="0"><thead><tr><th>现象</th><th>第一排查入口</th></tr></thead><tbody><tr><td>PVC Pending</td><td>StorageClass、CSI Pod、PV 事件</td></tr><tr><td>Pod 挂载失败</td><td>kubelet 日志、CSI 日志、后端权限</td></tr><tr><td>NFS 卡住</td><td>服务端状态、客户端 dmesg、网络连通</td></tr><tr><td>Ceph 写慢</td><td><code>ceph -s</code>、<code>ceph osd perf</code>、PG 状态</td></tr><tr><td>MinIO 403</td><td>用户 policy、bucket 权限</td></tr><tr><td>容量不释放</td><td>快照、版本控制、进程持有已删除文件</td></tr><tr><td>节点坏数据丢</td><td>Local PV 和备份策略</td></tr></tbody></table><h2 id="选型记录模板" tabindex="-1">选型记录模板 <a class="header-anchor" href="#选型记录模板" aria-label="Permalink to &quot;选型记录模板&quot;">​</a></h2><p>给一个具体服务选存储时，把这几项写清楚：</p><table tabindex="0"><thead><tr><th>项目</th><th>内容</th></tr></thead><tbody><tr><td>业务名称</td><td>哪个系统或服务用</td></tr><tr><td>数据类型</td><td>数据库 / 附件 / 备份 / 日志 / 制品</td></tr><tr><td>访问方式</td><td>块 / 文件 / 对象</td></tr><tr><td>读写模式</td><td>随机/顺序、小文件/大文件、并发量</td></tr><tr><td>容量</td><td>当前大小、增长速度、保留周期</td></tr><tr><td>可用性</td><td>单机可接受还是要求跨节点</td></tr><tr><td>备份</td><td>频率、保存位置、恢复演练记录</td></tr><tr><td>恢复要求</td><td>RTO/RPO——落到具体数值</td></tr><tr><td>运维</td><td>谁维护、常用命令、监控看板</td></tr><tr><td>风险</td><td>当前方案的单点、容量天花板、权限面</td></tr></tbody></table><p>落到具体场景的参数会自然推导出不同方案。&quot;附件目录 500G、每天增长 5G、多 Web Pod 读写、分钟级恢复&quot;和&quot;PostgreSQL 数据盘 2T、P99 延迟低于 2ms、RPO 5 分钟&quot;——这两个场景的存储选择会完全不同。选型不是选最好的技术方案，是选最匹配这些约束的方案。</p>',41)])])}const n=d(o,[["render",h]]);export{b as __pageData,n as default};
